SELECT COUNT(1) AS QUANTIDADE FROM LATTES_ORIENTACAO O JOIN SERVIDOR S ON S.PK_SIAPE = O.FK_SIAPE WHERE LOWER(COALESCE(S.AREA_INGRESSO, S.AREA_INGRESSO_OG, '')) LIKE '%matem%' AND S.SIGLA_CAMPUS = 'SEN' AND S.GENERO = 'MASCULINO' AND LOWER(COALESCE(O.TIPO, '')) LIKE '%iniciacao cientifica%' AND O.ANO IS NOT NULL AND O.ANO >= (CAST(strftime('%Y', 'now') AS INTEGER) - 4)